const input = $input.first().json;
const body = input.body || input;
const topic_id = body.topic_id;
const project_id = body.project_id;

// Auth check
const authHeader = input.headers?.authorization || '';
const expected = 'Bearer ' + $env.DASHBOARD_API_TOKEN;
if (authHeader !== expected) {
  throw new Error('Unauthorized');
}

if (!topic_id) throw new Error('topic_id is required');

return [{ json: { topic_id, project_id } }];

const visualResponse = $input.first().json;
const buildData = $('Build Visual Prompt').first().json;
const topic_id = buildData.topic_id;
const project_id = buildData.project_id;

if (visualResponse.error) {
  throw new Error(`Visual Assignment failed: ${visualResponse.error.message || JSON.stringify(visualResponse.error)}`);
}

let scenes = [];
try {
  const text = (visualResponse.content || []).filter(c => c.type === 'text').map(c => c.text).join('');
  const cleaned = text.replace(/^```(?:json)?\s*/m, '').replace(/\s*```$/m, '').trim();
  const s = cleaned.indexOf('[');
  const e = cleaned.lastIndexOf(']');
  if (s >= 0 && e > s) {
    scenes = JSON.parse(cleaned.substring(s, e + 1));
  }
} catch(err) {
  if (err.message.startsWith('Visual Assignment failed')) throw err;
  try {
    const text = (visualResponse.content || []).filter(c => c.type === 'text').map(c => c.text).join('');
    const objects = text.match(/\{[^{}]*"scene_number"[^{}]*\}/g) || [];
    scenes = objects.map(o => JSON.parse(o));
  } catch(e2) {
    scenes = [{ scene_number: 1, scene_id: 'scene_001', narration_text: buildData.combined_text.substring(0, 500), image_prompt: 'Documentary establishing shot', visual_type: 'static_image', emotional_beat: 'hook', chapter: 'Main' }];
  }
}

if (scenes.length === 0) {
  throw new Error('Scene segmentation produced 0 scenes');
}

const scenes_array = scenes.map((scene, i) => ({
  topic_id,
  project_id,
  scene_number: scene.scene_number || (i + 1),
  scene_id: scene.scene_id || `scene_${String(i + 1).padStart(3, '0')}`,
  narration_text: (scene.narration_text || '').replace(/^#+\s*/gm, '').replace(/\[.*?\]/g, '').replace(/\*\*/g, '').trim(),
  image_prompt: scene.image_prompt || 'Documentary scene',
  visual_type: 'static_image',
  emotional_beat: scene.emotional_beat || '',
  chapter: scene.chapter || '',
  audio_status: 'pending',
  image_status: 'pending',
  clip_status: 'pending',
  skipped: false
}));

const word_count = scenes_array.reduce((sum, s) => sum + (s.narration_text ? s.narration_text.split(' ').length : 0), 0);
const scene_count = scenes_array.length;

const script_json = JSON.stringify(scenes_array);
const script_metadata = JSON.stringify({
  video_metadata: {
    title: $('Assemble Script').first().json.topic.seo_title || $('Assemble Script').first().json.topic.original_title,
    description: `A detailed documentary about ${$('Assemble Script').first().json.topic.narrative_hook || ''}`,
    tags: ['documentary', $('Assemble Script').first().json.project.niche || ''],
    thumbnail_prompt: scenes_array[0]?.image_prompt || ''
  },
  generation_stats: { word_count, scene_count, quality_score: buildData.combined_score, force_passed: buildData.force_passed, attempt: buildData.attempt }
});

return [{ json: { scenes_array, script_json, script_metadata, word_count, scene_count, topic_id, project_id, combined_score: buildData.combined_score, force_passed: buildData.force_passed, attempt: buildData.attempt } }];

const errData = $input.first().json;
const topic_id = errData.topic_id || $('Validate Request').first().json?.topic_id;
const project_id = errData.project_id || $('Validate Request').first().json?.project_id;
const error_message = errData.error_message || errData.message || 'Unknown error in script generation';
return [{ json: { topic_id, project_id, error_message } }];

const SB = $env.SUPABASE_URL, SRK = $env.SUPABASE_SERVICE_ROLE_KEY;
const topicRaw = $('Read Topic').first().json;
const projRaw = $('Read Project').first().json;
const topic = Array.isArray(topicRaw) ? topicRaw[0] : topicRaw;
const project = Array.isArray(projRaw) ? projRaw[0] : projRaw;
const avResp = await fetch(SB + '/rest/v1/avatars?topic_id=eq.' + topic.id + '&select=*&limit=1', {
  headers: {'apikey': SRK, 'Authorization': 'Bearer ' + SRK}
});
const avatars = await avResp.json();
const avatar = avatars?.[0] || {};
return [{json: {topic, project, avatar, pass_number: 1}}];

const pass1 = $input.first().json;
const prep = $('Prep & Read Avatar').first().json;
const {topic, project, avatar} = prep;
const SB = $env.SUPABASE_URL, SRK = $env.SUPABASE_SERVICE_ROLE_KEY;

const passScores = {pass_1: {attempts: pass1.attempt, final_score: pass1.composite_score, verdict: pass1.verdict, scores: pass1.scores}};
await fetch(SB + '/rest/v1/topics?id=eq.' + topic.id, {
  method: 'PATCH',
  headers: {'apikey': SRK, 'Authorization': 'Bearer ' + SRK, 'Content-Type': 'application/json', 'Prefer': 'return=minimal'},
  body: JSON.stringify({script_pass_scores: passScores})
});

return [{json: {topic, project, avatar, pass_number: 2, pass1_output: pass1.pass_text, pass1_scores: passScores}}];

const pass2 = $input.first().json;
const handleP1 = $('Handle Pass 1 + Prep Pass 2').first().json;
const {topic, project, avatar, pass1_output, pass1_scores} = handleP1;
const SB = $env.SUPABASE_URL, SRK = $env.SUPABASE_SERVICE_ROLE_KEY, AK = $env.ANTHROPIC_API_KEY;

const passScores = {...pass1_scores, pass_2: {attempts: pass2.attempt, final_score: pass2.composite_score, verdict: pass2.verdict, scores: pass2.scores}};
await fetch(SB + '/rest/v1/topics?id=eq.' + topic.id, {
  method: 'PATCH',
  headers: {'apikey': SRK, 'Authorization': 'Bearer ' + SRK, 'Content-Type': 'application/json', 'Prefer': 'return=minimal'},
  body: JSON.stringify({script_pass_scores: passScores})
});

const pResp = await fetch(SB + '/rest/v1/system_prompts?prompt_type=eq.script_metadata_extractor&is_active=eq.true&select=prompt_text', {
  headers: {'apikey': SRK, 'Authorization': 'Bearer ' + SRK}
});
const extractPromptRaw = ((await pResp.json())?.[0]?.prompt_text) || '';
const extractPrompt = extractPromptRaw || 'Read the following script pass and extract:\n1. A 200-word summary of the content covered, argument structure, and emotional arc\n2. The primary case study character name and a 1-sentence description of where they are in their arc\n3. A list of ALL metaphors and analogies used\n4. A list of ALL reassurance phrases used\n5. A list of any other distinctive phrases that should not be repeated\n\nRESPOND IN JSON:\n{"summary": "", "character_name": "", "character_status": "", "metaphors_used": [], "reassurance_phrases_used": [], "notable_phrases": []}';

async function extract(text) {
  const prompt = extractPrompt + '\n\nSCRIPT:\n---\n' + text.substring(0, 60000) + '\n---';
  const r = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: {'Content-Type': 'application/json', 'x-api-key': AK, 'anthropic-version': '2023-06-01'},
    body: JSON.stringify({model: 'claude-sonnet-4-20250514', max_tokens: 4096, messages: [{role: 'user', content: prompt}]})
  });
  const d = await r.json();
  const txt = (d.content || []).filter(c => c.type === 'text').map(c => c.text).join('');
  try {
    const c = txt.replace(/^```(?:json)?\s*/m, '').replace(/\s*```$/m, '').trim();
    return JSON.parse(c.substring(c.indexOf('{'), c.lastIndexOf('}') + 1));
  } catch (e) {
    return {summary: txt.substring(0, 400), character_name: '', character_status: '', metaphors_used: [], reassurance_phrases_used: [], notable_phrases: []};
  }
}

const [p1Meta, p2Meta] = await Promise.all([extract(pass1_output), extract(pass2.pass_text)]);

return [{json: {
  topic, project, avatar, pass_number: 3,
  pass1_summary: p1Meta.summary || '',
  pass2_summary: p2Meta.summary || '',
  character_name: p1Meta.character_name || '',
  character_status: p2Meta.character_status || p1Meta.character_status || '',
  metaphors_used: [...(p1Meta.metaphors_used || []), ...(p2Meta.metaphors_used || [])],
  reassurance_phrases: [...(p1Meta.reassurance_phrases_used || []), ...(p2Meta.reassurance_phrases_used || [])],
  notable_phrases: [...(p1Meta.notable_phrases || []), ...(p2Meta.notable_phrases || [])],
  pass1_text: pass1_output, pass2_text: pass2.pass_text, passScores
}}];

const pass3 = $input.first().json;
const metaPrep = $('Extract Metadata + Prep Pass 3').first().json;
const {topic, project, pass1_text, pass2_text, passScores} = metaPrep;
const SB = $env.SUPABASE_URL, SRK = $env.SUPABASE_SERVICE_ROLE_KEY;

const combined_text = pass1_text + '\n\n' + pass2_text + '\n\n' + pass3.pass_text;
const word_count = combined_text.split(/\s+/).length;

const allScores = {...passScores, pass_3: {attempts: pass3.attempt, final_score: pass3.composite_score, verdict: pass3.verdict, scores: pass3.scores}};
const avgScore = ((allScores.pass_1?.final_score || 0) + (allScores.pass_2?.final_score || 0) + (allScores.pass_3?.final_score || 0)) / 3;

const scriptMeta = {
  video_title: topic.seo_title || topic.original_title,
  niche_category: project.niche,
  total_word_count: word_count,
  estimated_duration_minutes: Math.round(word_count / 200),
  pass_scores: allScores,
  total_api_calls: ((allScores.pass_1?.attempts || 1) + (allScores.pass_2?.attempts || 1) + (allScores.pass_3?.attempts || 1)) * 2 + 2,
  manual_review_flag: [allScores.pass_1, allScores.pass_2, allScores.pass_3].some(p => p?.verdict === 'FORCE_PASS' && (p?.final_score || 0) < 5),
  metaphors_used: metaPrep.metaphors_used || [],
  case_study_character: metaPrep.character_name || ''
};

await fetch(SB + '/rest/v1/topics?id=eq.' + topic.id, {
  method: 'PATCH',
  headers: {'apikey': SRK, 'Authorization': 'Bearer ' + SRK, 'Content-Type': 'application/json', 'Prefer': 'return=minimal'},
  body: JSON.stringify({
    script_json: {combined_text, pass_1: pass1_text, pass_2: pass2_text, pass_3: pass3.pass_text},
    script_quality_score: Math.round(avgScore * 10) / 10,
    script_evaluation: scriptMeta,
    script_pass_scores: allScores,
    script_metadata_extended: scriptMeta,
    word_count,
    scene_count: null
  })
});

return [{json: {combined_text, topic, project, word_count, script_metadata: scriptMeta}}];

